	}
	log.Debug("SSH key pair generated.")

	publicKey, err := ioutil.ReadFile(pubPath)
	ctx.SSHPublicKey = string(publicKey)
	return err
}

func parseSecurityRuleProtocol(proto string) (network.SecurityRuleProtocol, error) {
