func JsonKeys(b []byte) ([]string, error) {
	var keyMap map[string]interface{}

	err := json.Unmarshal(b, &keyMap)
	if err != nil {
		return []string{}, err
	}

	keys := make([]string, len(keyMap))
	ndx := 0
	for k := range keyMap {
		keys[ndx] = k
		ndx++
	}
	return keys, nil
}

