func compareDockerVersions(lhs, rhs dockerVersion) int {
	switch {
	case lhs.major < rhs.major:
		return -1
	case lhs.major > rhs.major:
		return 1
	case lhs.minor < rhs.minor:
		return -1
	case lhs.minor > rhs.minor:
		return 1
	}
	return 0
}

