	d.Set("vapp_transport", config.GetVmConfigInfo().OvfEnvironmentTransport)

	props := config.GetVmConfigInfo().Property
	if len(props) < 1 {
		return nil
	}
	vac := make(map[string]interface{})
	for _, v := range props {
		if v.Value != "" && v.Value != v.DefaultValue {
			vac[v.Id] = v.Value
		}
	}
	if len(vac) > 0 {
		return d.Set("vapp", []interface{}{
