func ReloadTheme(name string) {
	if name == defaultTheme {
		return
	}

	thememtx.Lock()
	if _, ok := themeManager.themes[name]; ok {
		delete(themeManager.themes, name)
	}
	thememtx.Unlock()

	themeManager.loadTheme(name)
}

func ThemeInfo(name string) ThemeDesc {
