func Capture(userSkip int) Stacktrace {
	var (
		skip   = userSkip + 1
		frames []Frame
	)
	for i := skip; ; i++ {
		pc, file, line, ok := runtime.Caller(i)
		if !ok {
			break
		}
		frames = append(frames, NewFrame(pc, file, line))
	}
	return Stacktrace{
		Frames: frames,
	}
}

