func ParseLine(n int, unsafeText []byte) (*Line, error) {
	linetype := LineTypePlain
	var comment []byte
	text := make([]byte, len(unsafeText))
	copy(text, unsafeText)
	if bytes.Contains(text, commentPrefix) {
		segs := bytes.Split(text, commentPrefix)
		text = segs[0]
		comment = segs[1]
	}
	var rx *regexp.Regexp
	for _, item := range matchTypes {
		if regexes[item.R].Match(text) {
			linetype = item.Type
			rx = regexes[item.R]
			break
		}
	}
	var d *Detail
	if linetype == LineTypeDetail || linetype == LineTypeParam {
		var err error
		d, err = parseDetail(text, rx)
		if err != nil {
			return nil, &ErrLine{N: n, Err: err}
		}
	}
	return &Line{
		Number:  n,
		Type:    linetype,
		Bytes:   text,
		Regexp:  rx,
		Comment: comment,
		detail:  d,
	}, nil
}

func (l *Line) Capture() string {
	if len(l.Comment) == 0 {
		return ""
	}
	matches := placeholderRegexp.FindSubmatch(l.Comment)
	if len(matches) < 2 {
		return ""
	}
	return string(matches[1])
}

func (l Lines) Bytes() []byte {
	var lines [][]byte
	for _, line := range l {
		lines = append(lines, line.Bytes)
	}
	return bytes.Join(lines, []byte("\n"))
}

func (v Value) Equal(val interface{}) bool {
	var str string
	var ok bool
	if str, ok = v.Data.(string); !ok {
		return v.Data == val
	}
	if isRegex(str) {
		regex := regexp.MustCompile(str[1 : len(str)-1])
		valStr := fmt.Sprintf("%v", val)
		if regex.Match([]byte(valStr)) {
			return true
		}
	}
	return fmt.Sprintf("%v", v.Data) == fmt.Sprintf("%v", val)
}

func (v Value) Type() string {
	var str string
	var ok bool
	if str, ok = v.Data.(string); !ok {
		return fmt.Sprintf("%T", v.Data)
	}
	if isRegex(str) {
		return "regex"
	}
	return "string"
}

