func (u *URL) Short() string {
	if u.Scheme == "" {
		return ""
	}

	s := schemeMap[u.Scheme].Aliases[0]

	if u.Scheme == "odbc" || u.Scheme == "oleodbc" {
		n := u.Proto
		if v, ok := schemeMap[n]; ok {
			n = v.Aliases[0]
		}
		s += "+" + n
	} else if u.Proto != "tcp" {
		s += "+" + u.Proto
	}

	s += ":"

	if u.User != nil {
		if un := u.User.Username(); un != "" {
			s += un + "@"
		}
	}

	if u.Host != "" {
		s += u.Host
	}

	if u.Path != "" && u.Path != "/" {
		s += u.Path
	}

	if u.Opaque != "" {
		s += u.Opaque
	}

	return s
}

func (u *URL) Normalize(sep, empty string, cut int) string {
	s := make([]string, 5)

	s[0] = u.Unaliased
	if u.Proto != "tcp" && u.Proto != "unix" {
		s[0] += "+" + u.Proto
	}

	if u.hostPortDB == nil {
		if u.Opaque != "" {
			u.hostPortDB = []string{u.Opaque, "", ""}
		} else {
			u.hostPortDB = []string{
				hostname(u.Host),
				hostport(u.Host),
				strings.TrimPrefix(u.Path, "/"),
			}
		}
	}
	copy(s[1:], u.hostPortDB)

	if u.User != nil {
		s[4] = u.User.Username()
	}

	for i := 0; i < len(s); i++ {
		if s[i] == "" {
			s[i] = empty
		}
	}

	if cut > 0 {
		i := len(s) - 1
		for ; i > cut; i-- {
			if s[i] != "" {
				break
			}
		}
		s = s[:i]
	}

	return strings.Join(s, sep)
}

func NewLimiter(
	client *redis.Client,
	hasher RateHasher,
	max int64,
) *RateLimiter {
	return &RateLimiter{
		redisClient: client,
		hasher:      hasher,
		max:         max,
	}
}

func (r *RateLimiter) Has(id string) (bool, error) {
	hash := r.hasher.Hash(id)
	return r.redisClient.Exists(hash).Result()
}

func (r *RateLimiter) Attempted(id string) (int64, error) {
	hash := r.hasher.Hash(id)
	val, err := r.redisClient.Get(hash).Result()

	if err != nil {
		if err == redis.Nil {
			return 0, nil
		}
		return 0, err
	}

	if err != nil {
		return 0, err
	}

	return strconv.ParseInt(val, 10, 64)
}

func (r *RateLimiter) Left(id string) (int64, error) {
	attempted, err := r.Attempted(id)
	if err != nil {
		return 0, err
	}

	left := r.max - attempted
	if left < 0 {
		return 0, nil
	}

	return left, nil
}

func (r *RateLimiter) Attempt(id string) (bool, error) {
	hash := r.hasher.Hash(id)

	exists := true

	val, err := r.redisClient.Get(hash).Result()
	if err != nil {
		if err == redis.Nil {
			exists = false
		} else {
			return false, err
		}
	}

	if exists {
		intVal, err := strconv.ParseInt(val, 10, 64)
		if err != nil {
			return false, err
		}

		if intVal >= r.max {
			return false, nil
		}
	}

	err = r.redisClient.Watch(func(rx *redis.Tx) error {
		_, err := rx.Pipelined(func(pipe *redis.Pipeline) error {
			if err := pipe.Incr(hash).Err(); err != nil {
				return err
			}

			return pipe.Expire(hash, r.hasher.Duration()).Err()
		})

		return err
	})

	if err != nil {
		return false, err
	}

	return true, nil
}

func IsPublicIP(ip net.IP) bool {
	if !ip.IsGlobalUnicast() {
		return false
	}

	for _, mask := range privateMasks {
		if mask.Contains(ip) {
			return false
		}
	}

	return true
}

func ParseForwarded(ipList string) string {
	for _, ip := range strings.Split(ipList, ",") {
		ip = strings.TrimSpace(ip)

		if parsed := net.ParseIP(ip); parsed != nil && IsPublicIP(parsed) {
			return ip
		}
	}

	return ""
}

