func Align(data []byte, bitSize int) []byte {

	actual:=len(data)	
	required:=bitSize >> 3

	if (bitSize % 8) > 0 {
		required++
	}

	if (actual >= required) {
		return data
	} 

	return append(bytes.Repeat([]byte{0}, required-actual), data...)
}

func Xor(left, right []byte) []byte {
	result := make([]byte, len(left))

	for i := 0; i < len(left); i++ {
		result[i] = left[i] ^ right[i]
	}

	return result
}

func Slice(arr []byte, count int) [][]byte {

	sliceCount := len(arr) / count
	result := make([][]byte, sliceCount)

	for i := 0; i < sliceCount; i++ {
		start := i * count
		end := i*count + count

		result[i] = arr[start:end]
	}

	return result
}

