func Dump(arr []byte) string {
	var buf bytes.Buffer

	buf.WriteString("(")
	buf.WriteString(fmt.Sprintf("%v", len(arr)))
	buf.WriteString(" bytes)[")

	for idx, b := range arr {
		buf.WriteString(fmt.Sprintf("%v", b))
		if idx != len(arr)-1 {
			buf.WriteString(", ")
		}
	}

	buf.WriteString("], Hex: [")

	for idx, b := range arr {
		buf.WriteString(fmt.Sprintf("%X", b))
		if idx != len(arr)-1 {
			buf.WriteString(" ")
		}
	}

	buf.WriteString("], Base64Url:")
	buf.WriteString(base64url.Encode(arr))

	return buf.String()
}

func Decode(data string) ([]byte,error) {
	data = strings.Replace(data, "-", "+", -1)
	data = strings.Replace(data, "_", "/", -1)

	switch(len(data) % 4) {
		case 0:
		case 2: data+="=="
		case 3:	data+="="
	}

	return base64.StdEncoding.DecodeString(data)
}

func Decode(token string, key interface{}) (string, map[string]interface{}, error) {

	payload, headers, err := DecodeBytes(token, key)

	if err != nil {
		return "", nil, err
	}

	return string(payload), headers, nil
}

func DecodeBytes(token string, key interface{}) ([]byte, map[string]interface{}, error) {
	parts, err := compact.Parse(token)

	if err != nil {
		return nil, nil, err
	}

	if len(parts) == 3 {
		return verify(parts, key)
	}

	if len(parts) == 5 {
		return decrypt(parts, key)
	}

	return nil, nil, errors.New(fmt.Sprintf("jwt.DecodeBytes() expects token of 3 or 5 parts, but was given: %v parts", len(parts)))
}

func DerivePBKDF2(password, salt []byte, iterationCount, keyBitLength int, h hash.Hash) []byte {

	prf := hmac.New(func() hash.Hash { return h }, password)
	hLen := prf.Size()
	dkLen := keyBitLength >> 3

	l := int(math.Ceil(float64(dkLen) / float64(hLen)))
	r := dkLen - (l-1)*hLen

	if dkLen > MaxInt {
		panic(fmt.Sprintf("kdf.DerivePBKDF2: expects derived key size to be not more that (2^32-1) bits, but was requested %v bits.", keyBitLength))
	}

	dk := make([]byte, 0, dkLen)

	for i := 0; i < l; i++ {

		t := f(salt, iterationCount, i+1, prf)

		if i == (l - 1) {
			t = t[:r]
		}

		dk = append(dk, t...)
	}

	return dk
}

func ReadPrivate(raw []byte) (key *ecdsa.PrivateKey,err error) {
	var encoded *pem.Block

	if encoded, _ = pem.Decode(raw); encoded == nil {
		return nil, errors.New("Ecc.ReadPrivate(): Key must be PEM encoded PKCS1 or PKCS8 EC private key")
	}

	var parsedKey interface{}

	if parsedKey,err=x509.ParseECPrivateKey(encoded.Bytes);err!=nil {
		if parsedKey, err = x509.ParsePKCS8PrivateKey(encoded.Bytes);err!=nil {
			return nil,err
		}
	}

	var ok bool

	if key,ok=parsedKey.(*ecdsa.PrivateKey);!ok {
		return nil, errors.New("Ecc.ReadPrivate(): Key is not valid *ecdsa.PrivateKey")
	}

	return key,nil
}

func ReadPublic(raw []byte) (key *rsa.PublicKey,err error)  {
	var encoded *pem.Block

	if encoded, _ = pem.Decode(raw); encoded == nil {
		return nil, errors.New("Rsa.NewPublic(): Key must be PEM encoded PKCS1 X509 certificate or PKIX public key")
	}

	var parsedKey interface{}
	var cert *x509.Certificate

	if parsedKey, err = x509.ParsePKIXPublicKey(encoded.Bytes); err != nil {
		if cert,err = x509.ParseCertificate(encoded.Bytes);err!=nil {
			return nil, err
		}

		parsedKey=cert.PublicKey
	}

	var ok bool

	if key, ok = parsedKey.(*rsa.PublicKey); !ok {
		return nil, errors.New("Rsa.NewPublic(): Key is not a valid RSA public key")
	}

	return key, nil
}

func AddPkcs7(data []byte, blockSize int) []byte {

	var paddingCount int

	if paddingCount = blockSize - (len(data) % blockSize);paddingCount == 0 {
		paddingCount=blockSize
	}		

	return append(data, bytes.Repeat([]byte{byte(paddingCount)}, paddingCount)...)
}

func RemovePkcs7(padded []byte, blockSize int) []byte {	

	dataLen:=len(padded)		
	paddingCount:=int(padded[dataLen-1])

	if(paddingCount > blockSize || paddingCount <= 0) {
		return padded
	}

	padding := padded[dataLen-paddingCount : dataLen-1]

	for _, b := range padding {
		if int(b) != paddingCount {
			return padded
		}
	}		

	return padded[:len(padded)-paddingCount]
}

