func msb32(x uint32) int {
	pos := 32
	temp := x >> 16
	if temp != 0 {
		pos -= 16
		x = temp
	}
	temp = x >> 8
	if temp != 0 {
		pos -= 8
		x = temp
	}
	temp = x >> 4
	if temp != 0 {
		pos -= 4
		x = temp
	}
	temp = x >> 2
	if temp != 0 {
		pos -= 2
		x = temp
	}
	temp = x >> 1
	if temp != 0 {
		return pos - 2
	}

	return int(uint32(pos) - x)
}

func msb64(n uint64) int {
	if n <= 0 {
		return -1
	}
	var r, v uint
	if n >= 1<<32 {
		r += 32
		v = uint(n >> 32)
	} else {
		v = uint(n)
	}
	if v >= 1<<16 {
		r += 16
		v >>= 16
	}
	if v >= 1<<8 {
		r += 8
		v >>= 8
	}
	if v >= 1<<4 {
		r += 4
		v >>= 4
	}
	if v >= 1<<2 {
		r += 2
		v >>= 2
	}
	r += v >> 1
	return int(r)
}

func EncodeAll(src []uint32) ([]uint32, error) {
	i := 0
	dst := make([]uint32, len(src))
	j := 0

	for {
		if i >= len(src) {
			break
		}
		remaining := src[i:]

		if canPack(remaining, 1, 28) {
			dst[j] = pack28(src[i : i+28])
			i += 28
		} else if canPack(remaining, 2, 14) {
			dst[j] = pack14(src[i : i+14])
			i += 14
		} else if canPack(remaining, 3, 9) {
			dst[j] = pack9(src[i : i+9])
			i += 9
		} else if canPack(remaining, 4, 7) {
			dst[j] = pack7(src[i : i+7])
			i += 7
		} else if canPack(remaining, 5, 5) {
			dst[j] = pack5(src[i : i+5])
			i += 5
		} else if canPack(remaining, 7, 4) {
			dst[j] = pack4(src[i : i+4])
			i += 4
		} else if canPack(remaining, 9, 3) {
			dst[j] = pack3(src[i : i+3])
			i += 3
		} else if canPack(remaining, 14, 2) {
			dst[j] = pack2(src[i : i+2])
			i += 2
		} else if canPack(remaining, 28, 1) {
			dst[j] = pack1(src[i : i+1])
			i += 1
		} else {
			return nil, fmt.Errorf("value out of bounds")
		}
		j += 1
	}
	return dst[:j], nil
}

func DecodeAll(dst, src []uint32) error {
	j := 0
	for _, v := range src {
		sel := v >> 28
		if sel >= 9 {
			return fmt.Errorf("invalid selector value: %b", sel)
		}
		selector[sel].unpack(v, dst[j:])
		j += selector[sel].n
	}
	return nil
}

func canPack(src []uint32, bits, n int) bool {
	if len(src) < n {
		return false
	}

	end := len(src)
	if n < end {
		end = n
	}

	max := uint32((2 << uint32(bits-1)) - 1)
	for i := 0; i < end; i++ {
		if src[i] > max {
			return false
		}
	}

	return true
}

func DecodeAll(dst, src []uint64) (value int, err error) {
	j := 0
	for _, v := range src {
		sel := v >> 60
		if sel >= 16 {
			return 0, fmt.Errorf("invalid selector value: %b", sel)
		}
		selector[sel].unpack(v, (*[240]uint64)(unsafe.Pointer(&dst[j])))
		j += selector[sel].n
	}
	return j, nil
}

func (c *Client) Out() []byte {
	if c.out.Len() == 0 {
		return nil
	}
	return c.out.Bytes()
}

func (c *Client) Step(in []byte) bool {
	c.out.Reset()
	if c.step > 2 || c.err != nil {
		return false
	}
	c.step++
	switch c.step {
	case 1:
		c.err = c.step1(in)
	case 2:
		c.err = c.step2(in)
	case 3:
		c.err = c.step3(in)
	}
	return c.step > 2 || c.err != nil
}

