func DecodeUnverifiedToken(buf []byte, ut *UnverifiedToken) error {
	b := bytes.Split(buf, tokenSep)
	if len(b) != 3 {
		return ErrInvalidToken
	}

	ut.Header = b[0]
	ut.Payload = b[1]
	ut.Signature = b[2]

	return nil
}

func (ks *Keystore) PublicKey() (crypto.PublicKey, bool) {
	ks.rw.RLock()
	key, pub := ks.Key, ks.PubKey
	ks.rw.RUnlock()
	if pub != nil {
		return pub, true
	}

	if key != nil {
		ks.rw.Lock()
		defer ks.rw.Unlock()

		if x, ok := key.(interface {
			Public() crypto.PublicKey
		}); ok {
			ks.PubKey = x.Public()
		}

		return ks.PubKey, ks.PubKey != nil
	}

	return nil, false
}

func (ks *Keystore) PrivateKey() (crypto.PrivateKey, bool) {
	ks.rw.RLock()
	defer ks.rw.RUnlock()
	return ks.Key, ks.Key != nil
}

