func (p Port) ToString() (out string) {
	out += fmt.Sprintf("Port %d/%s is %s\n", p.ID, p.Protocol, p.State)
	for _, script := range p.Scripts {
		output := ""
		for _, line := range strings.Split(script.Output, "\n") {
