func BalanceClosingHash(clientAddr, pscAddr common.Address, block uint32,
	offeringHash common.Hash, balance uint64) []byte {
	blockBytes := data.Uint32ToBytes(block)
	balanceBytes := data.Uint64ToBytes(balance)
	return crypto.Keccak256(
		[]byte("\x19Ethereum Signed Message:\n32"),
		crypto.Keccak256(
			[]byte("Privatix: receiver closing signature"),
			clientAddr.Bytes(),
			blockBytes[:],
			offeringHash.Bytes(),
			balanceBytes[:],
			pscAddr.Bytes(),
		),
	)
}

func Run(ctx context.Context, conf *Config,
	logger log.Logger, ports []uint16) {
	if conf.Mechanism == "" {
		logger.Debug("traversal NAT is not needed.")
		return
	}

	service, err := Parse(conf)
	if err != nil {
		logger.Error(err.Error())
		return
	}

	for k := range ports {
		service.DeleteMapping("tcp", int(ports[k]), int(ports[k]))

		name := fmt.Sprintf("service-%d", k)
		if err := Map(ctx, conf, logger, service, "tcp",
			int(ports[k]), int(ports[k]), name); err != nil {
			msg := fmt.Sprintf("failed to add port"+
				" mapping to %d port", ports[k])
			logger.Warn(msg)
			return
		}
	}

	extIP, err := ipify.GetIp()
	if err != nil {
		logger.Warn("failed to determine" +
			" a external ip address, error: " + err.Error())
		return
	}

	logger = logger.Add("externalIP", extIP)

	timeout := time.Duration(conf.CheckTimeout) * time.Millisecond

	checkSrv := func(port uint16) {
		if util.CheckConnection(
			"tcp", extIP, int(port), timeout) {
			logger.Info(fmt.Sprintf("port %d is available"+
				" on the Internet", port))
			return
		}
		logger.Warn(fmt.Sprintf("port %d is not available"+
			" on the Internet", port))
	}

	for k := range ports {
		checkSrv(ports[k])
	}
}

func RecoverPubKey(signer types.Signer, tx *types.Transaction) (*ecdsa.PublicKey, error) {
	V, R, S := tx.RawSignatureValues()
	hash := signer.Hash(tx)
	r, s := R.Bytes(), S.Bytes()
	sig := make([]byte, 65)
	copy(sig[32-len(r):32], r)
	copy(sig[64-len(s):64], s)
	sig[64] = byte(V.Uint64() - 27)
	pub, err := crypto.Ecrecover(hash[:], sig)
	if err != nil {
		return nil, err
	}
	return crypto.UnmarshalPubkey(pub)
}

func (h *Handler) GetTemplates(tkn, tplType string) ([]data.Template, error) {
	logger := h.logger.Add(
		"method", "GetTemplates", "type", tplType)

	if !h.token.Check(tkn) {
		logger.Warn("access denied")
		return nil, ErrAccessDenied
	}

	var templates []reform.Struct

	var err error
	if tplType != "" {
		templates, err = h.selectAllFrom(
			logger, data.TemplateTable,
			"WHERE kind = $1", tplType)
	} else {
		templates, err = h.selectAllFrom(
			logger, data.TemplateTable, "")
	}

	if err != nil {
		return nil, err
	}

	result := make([]data.Template, 0)

	for _, v := range templates {
		result = append(result, *v.(*data.Template))
	}

	return result, nil
}

func (h *Handler) CreateTemplate(
	tkn string, template *data.Template) (*string, error) {
	logger := h.logger.Add("method", "CreateTemplate",
		"template", template)

	if !h.token.Check(tkn) {
		logger.Warn("access denied")
		return nil, ErrAccessDenied
	}

	err := checkTemplate(logger, template)
	if err != nil {
		return nil, err
	}

	template.ID = util.NewUUID()
	template.Hash = data.HexFromBytes(crypto.Keccak256(template.Raw))

	err = h.insertObject(template)
	if err != nil {
		return nil, err
	}
	return &template.ID, nil
}

func (h *Handler) CreateProduct(tkn string,
	product data.Product) (*string, error) {
	logger := h.logger.Add("method", "CreateProduct", "product", product)

	if !h.token.Check(tkn) {
		logger.Warn("access denied")
		return nil, ErrAccessDenied
	}

	if product.ServiceEndpointAddress != nil &&
		!isValidSEAddress(*product.ServiceEndpointAddress) {
		return nil, ErrBadServiceEndpointAddress
	}

	product.ID = util.NewUUID()
	if err := insert(logger, h.db.Querier, &product); err != nil {
		return nil, err
	}

	return &product.ID, nil
}

func (h *Handler) UpdateProduct(tkn string, product data.Product) error {
	logger := h.logger.Add("method", "UpdateProduct", "product", product)

	if !h.token.Check(tkn) {
		logger.Warn("access denied")
		return ErrAccessDenied
	}

	oldProduct := &data.Product{}
	if err := h.findByPrimaryKey(logger,
		ErrProductNotFound, oldProduct, product.ID); err != nil {
		return err
	}

	if product.Salt == 0 {
		product.Salt = oldProduct.Salt
	}

	if product.Password == "" {
		product.Password = oldProduct.Password
	}

	if product.ServiceEndpointAddress != nil &&
		!isValidSEAddress(*product.ServiceEndpointAddress) {
		return ErrBadServiceEndpointAddress
	}

	if err := update(logger, h.db.Querier, &product); err != nil {
		logger.Error(err.Error())
		return ErrInternal
	}

	return nil
}

