func EncryptedKey(pkey *ecdsa.PrivateKey, auth string) (Base64String, error) {
	key := keystore.NewKeyForDirectICAP(rand.Reader)
	key.Address = crypto.PubkeyToAddress(pkey.PublicKey)
	key.PrivateKey = pkey
	encryptedBytes, err := keystore.EncryptKey(key, auth,
		keystore.StandardScryptN,
		keystore.StandardScryptP)
	if err != nil {
		return "", err
	}
	return FromBytes(encryptedBytes), nil
}

func ExecuteCommand(args []string) error {
	if len(args) == 0 {
		return nil
	}

	switch args[0] {
	case "db-create":
		f := readFlags(args)
		if err := createDatabase(f.connection); err != nil {
			panic("failed to create database: " + err.Error())
		}
		os.Exit(0)
	case "db-migrate":
		f := readFlags(args)
		err := migration.Migrate(f.connection, f.version)
		if err != nil {
			panic("failed to run migration: " + err.Error())
		}
		os.Exit(0)
	case "db-init-data":
		f := readFlags(args)
		if err := initData(f.connection); err != nil {
			panic("failed to init database: " + err.Error())
		}
		os.Exit(0)
	case "db-version":
		f := readFlags(args)
		version, err := migration.Version(f.connection)
		if err != nil {
			msg := "failed to print database schema version: "
			panic(msg + err.Error())
		}
		fmt.Println("database schema version:", version)
		os.Exit(0)
	}
	return nil
}

