func (s *Server) HandleFunc(pattern string, handler HandlerFunc) {
	s.Mux().HandleFunc(pattern,
		func(w http.ResponseWriter, r *http.Request) {
			handler(w, r, &Context{})
		})
}

func (s *Server) RequireHTTPMethods(logger log.Logger,
	handler HandlerFunc, methods ...string) HandlerFunc {
	l := logger.Add("method", "RequireHTTPMethods")
	return func(w http.ResponseWriter, r *http.Request, ctx *Context) {
		for _, v := range methods {
			if v == r.Method {
				handler(w, r, ctx)
				return
			}
		}

		l.Add("sender", r.RemoteAddr).Warn("not allowed HTTP method")
		s.RespondError(logger, w, ErrMethodNotAllowed)
	}
}

func (s *Server) RequireBasicAuth(logger log.Logger,
	handler HandlerFunc, auth AuthFunc) HandlerFunc {
	l := logger.Add("method", "RequireBasicAuth")
	return func(w http.ResponseWriter, r *http.Request, ctx *Context) {
		name, pass, ok := r.BasicAuth()
		if !ok || !auth(name, pass) {
			l.Add("sender", r.RemoteAddr).Warn("access denied")
			s.RespondError(logger, w, ErrAccessDenied)
			return
		}

		ctx.Username = name
		handler(w, r, ctx)
	}
}

func New(db *reform.DB, logger log.Logger, payAddr string,
	timeout uint) (*Service, error) {
	return &Service{
		db:      db,
		msgChan: make(chan *req),
		payAddr: payAddr,
		timeout: time.Duration(timeout) * time.Millisecond,
		logger:  logger.Add("type", "messages/ept.Service"),
	}, nil
}

func (s *Service) EndpointMessage(channelID string) (*Message, error) {
	c := make(chan *result)
	done := make(chan bool)

	req := &req{channelID: channelID, callback: c, done: done}

	go s.processing(req)

	select {
	case result := <-c:
		return result.msg, result.err
	case <-time.After(s.timeout):
		close(done)
		return nil, ErrTimeOut
	}
}

func (h *Handler) ConnChange(ctx context.Context,
	product, productPassword string) (*rpc.Subscription, error) {
	logger := h.logger.Add("method", "ConnChange", "product", product)

	logger.Info("subscribing to adapter connection changes")

	_, err := h.checkProductPassword(logger, product, productPassword)
	if err != nil {
		return nil, err
	}

	ntf, ok := rpc.NotifierFromContext(ctx)
	if !ok {
		logger.Error("no notifier found in context")
		return nil, ErrInternal
	}

	sub := ntf.CreateSubscription()
	cb := func(job *data.Job, result error) {
		if result == nil {
			h.handleConnChange(product, logger, ntf, sub, job)
		}
	}
	jobTypes := []string{
		data.JobClientPreServiceSuspend,
		data.JobClientPreServiceUnsuspend,
		data.JobClientPreServiceTerminate,
	}

	sid := string(sub.ID)
	if err = h.queue.Subscribe(jobTypes, sid, cb); err != nil {
		logger.Error(err.Error())
		return nil, ErrInternal
	}

	go func() {
		for err, ok := <-sub.Err(); ok; {
			if err != nil {
				logger.Warn(err.Error())
			}
		}

		err := h.queue.Unsubscribe(jobTypes, sid)
		if err != nil {
			logger.Error(err.Error())
		}
	}()

	return sub, nil
}

func FromBase64ToHex(s Base64String) (string, error) {
	b, err := ToBytes(s)
	if err != nil {
		return "", err
	}
	return hex.EncodeToString(b), nil
}

func HexToBytes(s HexString) ([]byte, error) {
	s2 := string(s)
	if strings.HasPrefix(s2, "0x") || strings.HasPrefix(s2, "0X") {
		s2 = s2[2:]
	}
	return hex.DecodeString(s2)
}

func ToBytes(s Base64String) ([]byte, error) {
	return base64.URLEncoding.DecodeString(strings.TrimSpace(string(s)))
}

func ToHash(h Base64String) (common.Hash, error) {
	hashBytes, err := ToBytes(h)
	if err != nil {
		err = fmt.Errorf("unable to parse ethereum hash: %s", err)
	}
	return common.BytesToHash(hashBytes), err
}

func HexToHash(h HexString) (common.Hash, error) {
	hashBytes, err := HexToBytes(h)
	if err != nil {
		err = fmt.Errorf("unable to parse ethereum hash: %s", err)
	}
	return common.BytesToHash(hashBytes), err
}

func HexToAddress(addr HexString) (common.Address, error) {
	addrBytes, err := HexToBytes(addr)
	if err != nil {
		err = fmt.Errorf("unable to parse ethereum addr: %s", err)
	}
	return common.BytesToAddress(addrBytes), err
}

func BytesToUint32(b []byte) (uint32, error) {
	if len(b) != 4 {
		return 0, fmt.Errorf("wrong len")
	}
	return binary.BigEndian.Uint32(b), nil
}

func Uint32ToBytes(x uint32) [4]byte {
	var xBytes [4]byte
	binary.BigEndian.PutUint32(xBytes[:], x)
	return xBytes
}

func Uint64ToBytes(x uint64) [8]byte {
	var xBytes [8]byte
	binary.BigEndian.PutUint64(xBytes[:], x)
	return xBytes
}

func Uint192ToBytes(x *big.Int) [24]byte {
	var ret [24]byte
	xBytes := x.Bytes()
	for i, v := range xBytes {
		ret[24-len(xBytes)+i] = v
	}
	return ret
}

func HashPassword(password, salt string) (Base64String, error) {
	salted := []byte(password + salt)
	passwordHash, err := bcrypt.GenerateFromPassword(salted, bcrypt.DefaultCost)
	if err != nil {
		return "", err
	}
	return FromBytes(passwordHash), nil
}

func ValidatePassword(hash Base64String, password, salt string) error {
	salted := []byte(fmt.Sprint(password, salt))
	hashB, err := ToBytes(hash)
	if err != nil {
		return err
	}
	return bcrypt.CompareHashAndPassword(hashB, salted)
}

func GetUint64Setting(db *reform.DB, key string) (uint64, error) {
	var setting Setting
	err := db.FindByPrimaryKeyTo(&setting, key)
	if err != nil {
		if err == sql.ErrNoRows {
			return 0, fmt.Errorf("key %s is not exist"+
				" in Setting table", key)
		}
		return 0, err
	}

	value, err := strconv.ParseUint(setting.Value, 10, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse %s setting: %v",
			key, err)
	}

	return value, nil

}

func ChannelKey(client, agent HexString, block uint32,
	offeringHash HexString) ([]byte, error) {
	clientAddr, err := HexToAddress(client)
	if err != nil {
		return nil, err
	}

	agentAddr, err := HexToAddress(agent)
	if err != nil {
		return nil, err
	}

	hash, err := base64.URLEncoding.DecodeString(
		strings.TrimSpace(string(offeringHash)))
	if err != nil {
		return nil, err
	}

	blockBytes := Uint32ToBytes(block)

	return crypto.Keccak256(clientAddr.Bytes(),
		agentAddr.Bytes(), blockBytes[:],
		common.BytesToHash(hash).Bytes()), nil
}

func MinDeposit(offering *Offering) uint64 {
	return offering.MinUnits*offering.UnitPrice + offering.SetupPrice
}

func (h *Handler) AcceptOffering(tkn string, account data.HexString,
	offering string, deposit, gasPrice uint64) (*string, error) {
	logger := h.logger.Add("method", "AcceptOffering",
		"account", account, "offering", offering,
		"deposit", deposit, "gasPrice", gasPrice)

	if !h.token.Check(tkn) {
		logger.Warn("access denied")
		return nil, ErrAccessDenied
	}

	var acc data.Account
	if err := h.findByColumn(logger, ErrAccountNotFound,
		&acc, "eth_addr", account); err != nil {
		return nil, err
	}

	offer, err := h.findActiveOfferingByID(logger, offering)
	if err != nil {
		return nil, err
	}

	minDeposit := data.MinDeposit(offer)

	if deposit == 0 {
		deposit = minDeposit
	} else if deposit < minDeposit {
		logger.Error(ErrDepositTooSmall.Error())
		return nil, ErrDepositTooSmall
	}

	if err := h.pingOffering(logger, offer); err != nil {
		return nil, err
	}

	rid := util.NewUUID()
	jobData := &worker.ClientPreChannelCreateData{Account: acc.ID,
		Offering: offering, GasPrice: gasPrice, Deposit: deposit}
	if err := job.AddWithData(h.queue, nil, data.JobClientPreChannelCreate,
		data.JobChannel, rid, data.JobUser, jobData); err != nil {
		logger.Error(err.Error())
		return nil, ErrInternal
	}

	return &rid, nil
}

func (h *Handler) ChangeOfferingStatus(
	tkn, offering, action string, gasPrice uint64) error {
	logger := h.logger.Add("method", "ChangeOfferingStatus",
		"offering", offering, "action", action, "gasPrice", gasPrice)

	if !h.token.Check(tkn) {
		logger.Warn("access denied")
