	path string, req *Request) (*http.Request, error) {
	return NewHTTPRequestWithURL(method, GetURL(conf, path), req)
}

func NewHTTPRequestWithURL(method, url string, req *Request) (*http.Request, error) {
	data, err := json.Marshal(req)
	if err != nil {
		return nil, err
	}

	return http.NewRequest(
		method, url, bytes.NewReader(data))
}

func Send(req *http.Request) (*Response, error) {
	client := &http.Client{}

	resp, err := client.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	var resp2 Response
	if err = json.NewDecoder(resp.Body).Decode(&resp2); err != nil {
		return nil, err
	}

	return &resp2, nil
}

func (t *SimpleToken) Check(s string) bool {
	t.mtx.RLock()
	defer t.mtx.RUnlock()
	return s == t.token
}

func (t *SimpleToken) Make() (string, error) {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		return "", err
	}
	t.mtx.Lock()
	defer t.mtx.Unlock()
	t.token = string(data.FromBytes(b))
	return t.token, nil
}

