func (e *encoder) nextSpecialChar(p []byte) (i int) {
	for i = 0; i < len(p); i++ {
		if !((p[i] >= 32 && p[i] <= 126 && p[i] != byte('=')) || p[i] == byte('\t')) {
			return i
		}
	}
	return i
}

func (d *decoder) nextSpecialChar(p []byte) (i int) {
	for i = 0; i < len(p); i++ {
		if p[i] == byte('=') || (d.enc.isText && p[i] == byte('\r')) {
			return i
		}
	}
	return i
}

