func Contains(s string, substrs []string) bool {
	for _, substr := range substrs {
		if strings.Contains(s, substr) {
			return true
		}
	}

	return false
}

func RemoveStringsFromString(s string, substrs []string) string {
	for loop := true; loop; {
		loop = false
		for _, substr := range substrs {
			lastS := s
			s = strings.Join(strings.Split(s, substr), "")
			if lastS != s {
				loop = true
				break
			}
		}
	}

	return s
}

func Map(ss []string, callback func(string) string) []string {
	newStrings := make([]string, len(ss))
	for i, s := range ss {
		newStrings[i] = callback(s)
	}

	return newStrings
}

func Equal(a, b []string) bool {
	if len(a) != len(b) {
		return false
	}
	for i, v := range a {
		if v != b[i] {
			return false
		}
	}
	return true
}

func Uniq(items []string) (uniqItems []string) {
	sort.Strings(items)

	lastitem := ""
	for _, item := range items {
		if item != lastitem {
			uniqItems = append(uniqItems, item)
			lastitem = item
		}
	}

	return
}

