	defer l.key.RUnlock()

	builder := bytes.NewBufferString("[")

	for i, entry := range l.underlyer {
		if i >= 15 {
			builder.WriteString("... ")
			break
		}
		builder.WriteString(fmt.Sprintf("%v ", entry))
	}
	builder.Truncate(builder.Len() - 1)
	builder.WriteRune(']')
	return builder.String()
}

func (l *List) Swap(x, y uint) bool {
	l.key.Lock()
	defer l.key.Unlock()
	return l.swap(x, y)
}

func (l List) MarshalText() (text []byte, err error) {
	var buf bytes.Buffer
	l.writeToBuffer(&buf)
	return buf.Bytes(), nil
}

func (l *List) UnmarshalText(text []byte) error {
	m := parse.Bytes(text)
	defer m.Release()
	capacity := len(m.List)
	if len(m.Text) == 0 {
		capacity += 2
	}
	list := make(List, 0, capacity)

	if len(m.Text) > 0 {
		list = append(list, "msg", string(m.Text))
	}
	for _, v := range m.List {
		list = append(list, string(v))
	}
	*l = list
	return nil
}

func repl(match string, t time.Time) string {
	if match == "%%" {
		return "%"
	}

	formatFunc, ok := formats[match]
	if ok {
		return formatFunc(t)
	}
	return formatNanoForMatch(match, t)
}

func Format(format string, t time.Time) string {
	fn := func(match string) string {
		return repl(match, t)
	}
	return fmtRe.ReplaceAllStringFunc(format, fn)
}

func Monotonic() time.Duration {
	sec, nsec := monotime()
