	}
	return nil, fmt.Errorf("listener is closed")
}

func (d *Dialer) AddDialer(pd transport.Dialer) {
	d.Dialers = append(d.Dialers, pd)
}

func (d *Dialer) subDialerForAddr(raddr ma.Multiaddr) transport.Dialer {
	for _, pd := range d.Dialers {
		if pd.Matches(raddr) {
			return pd
		}
	}

	if d.fallback.Matches(raddr) {
		return d.fallback
	}

	return nil
}

func (d *Dialer) rawConnDial(ctx context.Context, raddr ma.Multiaddr, remote peer.ID) (transport.Conn, error) {
	if strings.HasPrefix(raddr.String(), "/ip4/0.0.0.0") {
		log.Event(ctx, "connDialZeroAddr", lgbl.Dial("conn", d.LocalPeer, remote, nil, raddr))
		return nil, fmt.Errorf("Attempted to connect to zero address: %s", raddr)
	}

	sd := d.subDialerForAddr(raddr)
	if sd == nil {
		return nil, fmt.Errorf("no dialer for %s", raddr)
	}

	return sd.DialContext(ctx, raddr)
}

func MultiaddrProtocolsMatch(a, b ma.Multiaddr) bool {
	ap := a.Protocols()
	bp := b.Protocols()

	if len(ap) != len(bp) {
		return false
	}

	for i, api := range ap {
		if api.Code != bp[i].Code {
			return false
		}
	}

	return true
}

func MultiaddrNetMatch(tgt ma.Multiaddr, srcs []ma.Multiaddr) ma.Multiaddr {
	for _, a := range srcs {
		if MultiaddrProtocolsMatch(tgt, a) {
			return a
		}
	}
	return nil
}

func get(values map[string]interface{}, key string) interface{} {
	if len(key) == 0 || values == nil {
		return nil
	}

	key = strings.ToLower(key)
	val, ok := values[key]

	if ok {
		switch val.(type) {
		case []interface{}:
			return nil
		default:
			return val
		}
	}

	return nil
}

func getArray(values map[string]interface{}, key string) []interface{} {
	if len(key) == 0 || values == nil {
		return nil
	}

	key = strings.ToLower(key)
	val, ok := values[key]

	if ok {
		switch v := val.(type) {
		case []interface{}:
			return v
		default:
			retVal := make([]interface{}, 1)
			retVal[0] = val
			return retVal
		}
	}

	return nil
}

func buildParams(options *ImageOptions) ([]string, error) {
	a := []string{}

	if options.Input == "" {
		return []string{}, errors.New("Must provide input")
	}

	a = append(a, "-q")
	a = append(a, "--disable-plugins")

	a = append(a, "--format")
	if options.Format != "" {
		a = append(a, options.Format)
	} else {
		a = append(a, "png")
	}

	if options.Height != 0 {
		a = append(a, "--height")
		a = append(a, strconv.Itoa(options.Height))
	}

	if options.Width != 0 {
		a = append(a, "--width")
		a = append(a, strconv.Itoa(options.Width))
	}

	if options.Quality != 0 {
		a = append(a, "--quality")
		a = append(a, strconv.Itoa(options.Quality))
	}

	if options.Input != "-" {
		options.Html = ""
	}

	a = append(a, options.Input)

	if options.Output == "" {
		a = append(a, "-")
	} else {
		a = append(a, options.Output)
	}

	return a, nil
}

func unsetenvGPGAgentInfo() {
	v := C.CString("GPG_AGENT_INFO=")
	defer C.free(unsafe.Pointer(v))
	C.putenv(v)
}

func (c *Context) AssuanSend(
	cmd string,
	data AssuanDataCallback,
	inquiry AssuanInquireCallback,
	status AssuanStatusCallback,
) error {
	var operr C.gpgme_error_t

	dataPtr := callbackAdd(&data)
	inquiryPtr := callbackAdd(&inquiry)
	statusPtr := callbackAdd(&status)
	cmdCStr := C.CString(cmd)
	defer C.free(unsafe.Pointer(cmdCStr))
	err := C.gogpgme_op_assuan_transact_ext(
		c.ctx,
		cmdCStr,
		C.uintptr_t(dataPtr),
		C.uintptr_t(inquiryPtr),
		C.uintptr_t(statusPtr),
		&operr,
	)

	if handleError(operr) != nil {
		return handleError(operr)
	}
	return handleError(err)
}

func NewData() (*Data, error) {
	d := newData()
	return d, handleError(C.gpgme_data_new(&d.dh))
}

func NewDataFile(f *os.File) (*Data, error) {
	d := newData()
	return d, handleError(C.gpgme_data_new_from_fd(&d.dh, C.int(f.Fd())))
}

func NewDataBytes(b []byte) (*Data, error) {
	d := newData()
	var cb *C.char
	if len(b) != 0 {
		cb = (*C.char)(unsafe.Pointer(&b[0]))
	}
	return d, handleError(C.gpgme_data_new_from_mem(&d.dh, cb, C.size_t(len(b)), 1))
}

func NewDataReader(r io.Reader) (*Data, error) {
	d := newData()
	d.r = r
	d.cbs.read = C.gpgme_data_read_cb_t(C.gogpgme_readfunc)
	cbc := callbackAdd(d)
	d.cbc = cbc
	return d, handleError(C.gogpgme_data_new_from_cbs(&d.dh, &d.cbs, C.uintptr_t(cbc)))
}

func NewDataWriter(w io.Writer) (*Data, error) {
	d := newData()
	d.w = w
	d.cbs.write = C.gpgme_data_write_cb_t(C.gogpgme_writefunc)
	cbc := callbackAdd(d)
	d.cbc = cbc
	return d, handleError(C.gogpgme_data_new_from_cbs(&d.dh, &d.cbs, C.uintptr_t(cbc)))
}

func NewDataReadWriter(rw io.ReadWriter) (*Data, error) {
	d := newData()
	d.r = rw
	d.w = rw
	d.cbs.read = C.gpgme_data_read_cb_t(C.gogpgme_readfunc)
	d.cbs.write = C.gpgme_data_write_cb_t(C.gogpgme_writefunc)
	cbc := callbackAdd(d)
	d.cbc = cbc
	return d, handleError(C.gogpgme_data_new_from_cbs(&d.dh, &d.cbs, C.uintptr_t(cbc)))
}

func (d *Data) Close() error {
	if d.dh == nil {
		return nil
	}
	if d.cbc > 0 {
		callbackDelete(d.cbc)
	}
	_, err := C.gpgme_data_release(d.dh)
	d.dh = nil
	return err
}

func (d *Data) Name() string {
	return C.GoString(C.gpgme_data_get_file_name(d.dh))
}

func NewCommand(name string, args ...string) *Command {
	return &Command{
		name: name,
		args: args,
	}
}

func (c *Command) Arg(v interface{}) *Command {
	c.args = append(c.args, fmt.Sprintf("%v", v))
	return c
}

func (c Command) String() string {
	s := fmt.Sprintf("COMMAND [%d] %s", time.Now().Unix(), c.name)
	if len(c.args) > 0 {
		s += ";" + strings.Join(c.args, ";")
	}
	s += "\n\n"

	return s
}

func (r Record) Columns() []string {
	cols := []string{}
	for k := range r {
		cols = append(cols, k)
	}
	sort.Strings(cols)

	return cols
}

func (r Record) Get(column string) (interface{}, error) {
	v, ok := r[column]
	if !ok {
		return nil, ErrUnknownColumn
	}

	return v, nil
}

func (r Record) GetBool(column string) (bool, error) {
	v, err := r.getKey(reflect.Float64, column)
	if err != nil {
		return false, err
	}

	return v == 1.0, nil
}

func (r Record) GetInt(column string) (int64, error) {
	v, err := r.getKey(reflect.Float64, column)
	if err != nil {
		return 0, err
	}

	return int64(v.(float64)), nil
}

func (r Record) GetSlice(column string) ([]interface{}, error) {
	v, err := r.getKey(reflect.Slice, column)
	if err != nil {
		return nil, err
	}

	rv := reflect.ValueOf(v)
	n := rv.Len()
	out := make([]interface{}, n)

	for i := 0; i < n; i++ {
		out[i] = rv.Index(i).Interface()
	}

	return out, nil
}

func (r Record) GetString(column string) (string, error) {
	v, err := r.getKey(reflect.String, column)
	if err != nil {
		return "", err
	}

	return v.(string), nil
}

func (r Record) GetTime(column string) (time.Time, error) {
	v, err := r.getKey(reflect.Float64, column)
	if err != nil {
		return time.Time{}, err
	}

	return time.Unix(int64(v.(float64)), 0), nil
}

