func (c *Client) Exec(r Request) (*Response, error) {
	var err error

	if c.conn == nil {
		c.conn, err = c.dialer.Dial(c.network, c.address)
		if err != nil {
			return nil, err
		}

		if r.keepAlive() {
			switch c.network {
			case "tcp":
				c.conn.(*net.TCPConn).SetKeepAlive(true)
			}
		} else {
			defer c.Close()
		}
	}

	return r.handle(c.conn)
}

