func (s *VecStack) Push(value *Vec) {
	s.top = &item{value, s.top}
	s.size++
}

func (s *VecStack) Pop() (value *Vec) {
	if s.size > 0 {
		value, s.top = s.top.value, s.top.next
		s.size--
		return
	}
	return nil
}

func (s *VecStack) PopLast() (value *Vec) {
	if lastElem := s.popLast(s.top); s.size >= 2 && lastElem != nil {
		return lastElem.value
	}
	return nil
}

func (s *VecStack) Peek() (value *Vec, exists bool) {
	exists = false
	if s.size > 0 {
		value = s.top.value
		exists = true
	}
	return
}

func (s *VecStack) PeekN(n int) []*Vec {
	var (
		N   []*Vec
		cur *item
	)
	N = make([]*Vec, 0, n)
	cur = s.top
	for len(N) < n {
		if cur == nil {
			break
		}
		N = append(N, cur.value)
		cur = cur.next
	}
	return N
}

