func NewServer(opts *ServerOptions) *Server {
	server := &Server{
		signer:          opts.Signer,
		verifier:        opts.Verifier,
		isProcessor:     hasProcessor(opts),
		isController:    hasController(opts),
		headers:         http.Header{},
		processorDomain: opts.ProcessorDomain,
	}
	server.headers.Set("Accept", "application/json")
	server.headers.Set("Content-Type", "application/json")
	if hasProcessor(opts) {
		server.headers.Set("X-OpenGDPR-ProcessorDomain", opts.ProcessorDomain)
	}
	router := httprouter.New()
	hm := buildHandlerMap(opts)
	for path, methods := range hm {
		for method, builder := range methods {
			router.Handle(method, path, server.handle(builder(opts)))
		}
	}
	server.handlerFn = router.ServeHTTP
	return server
}

func Callback(cbReq *CallbackRequest, opts *CallbackOptions) error {
	client := opts.Client
	if client == nil {
		client = http.DefaultClient
	}
	buf := bytes.NewBuffer(nil)
	err := json.NewEncoder(buf).Encode(cbReq)
	if err != nil {
		return err
	}
	signature, err := opts.Signer.Sign(buf.Bytes())
	if err != nil {
		return err
	}
	req, err := http.NewRequest("POST", cbReq.StatusCallbackUrl, buf)
	if err != nil {
		return err
	}
	req.Header.Set("X-OpenGDPR-Processor-Domain", opts.ProcessorDomain)
	req.Header.Set("X-OpenGDPR-Signature", signature)
	for i := 0; i < opts.MaxAttempts; i++ {
		resp, err := client.Do(req)
		if err != nil || resp.StatusCode != 200 {
			time.Sleep(opts.Backoff)
			continue
		}
		return nil
	}
	return fmt.Errorf("callback timed out for %s", cbReq.StatusCallbackUrl)
}

