func MakeHub(config HubConfig) (Hub, error) {
	if config == nil {
		return NewHub(), nil
	}

	driverName := getDriverName(config)
	if len(driverName) == 0 {
		return nil, fmt.Errorf("driver name is not specified")
	}
	d, ok := drivers[driverName]
	if ok {
		h, err := d.Create(config)
		if err != nil {
			log.Errorf("unable to connect to %s pubsub server: %+v", driverName, err)
			return nil, err
		}
		log.Info("connected to %s pubsub", driverName)
		return h, nil
	}

	return nil, fmt.Errorf("unknown driver: %s", driverName)
}

func Fib() func() time.Duration {
	a, b := 0, 1
	return func() time.Duration {
		a, b = b, a+b
		return time.Duration(a*10) * time.Millisecond
	}
}

func roundIndex(start, max int) []int {
	if start < 0 {
		start = 0
	}
	result := make([]int, max)
	for i := 0; i < max; i++ {
		if start+i < max {
			result[i] = start + i
		} else {
			result[i] = int(math.Abs(float64(max - (start + i))))
		}
	}
	return result
}

