func NewCachedLoader(namespace string, consulAddr string) (config.Loader, error) {
	config := api.DefaultConfig()
	config.Address = consulAddr
	consul, err := api.NewClient(config)
	if err != nil {
		return nil, fmt.Errorf("Could not connect to consul: %v", err)
	}

	return &cachedLoader{namespace: namespace, consulKV: consul.KV()}, nil
}

func (c *cachedLoader) Import(data []byte) error {
	conf := make(map[string]interface{})
	err := json.Unmarshal(data, &conf)
	if err != nil {
		return fmt.Errorf("Unable to parse json data: %v", err)
	}
	kvMap, err := c.compileKeyValues(conf, c.namespace)
	if err != nil {
		return fmt.Errorf("Unable to complie KVs: %v", err)
	}

	if err != nil {
		return fmt.Errorf("Could not create consul client: %v", err)
	}
	for k, v := range kvMap {
		p := &api.KVPair{Key: k, Value: v}
		_, err = c.consulKV.Put(p, nil)
		if err != nil {
			return fmt.Errorf("Could not write key to consul (%s | %s) %v", k, v, err)
		}
	}
	return nil
}

func (c *cachedLoader) Initialize() error {
	pairs, _, err := c.consulKV.List(c.namespace, nil)
	if err != nil {
		return fmt.Errorf("Could not pull config from consul: %v", err)
	}

	c.cacheLock.Lock()
	defer c.cacheLock.Unlock()

	c.cache = make(map[string][]byte)
	for _, kv := range pairs {
		c.cache[kv.Key] = kv.Value
	}
	return nil
}

func (c *cachedLoader) Get(key string) ([]byte, error) {
	c.cacheLock.RLock()
	defer c.cacheLock.RUnlock()

	compiledKey := c.namespace + divider + key
	if ret, ok := c.cache[compiledKey]; ok {
		return ret, nil
	}
	return nil, fmt.Errorf("Could not find value for key: %s", compiledKey)
}

func (c *cachedLoader) MustGetString(key string) string {
	b, err := c.Get(key)
	if err != nil {
		panic(fmt.Sprintf("Could not fetch config (%s) %v", key, err))
	}

	var s string
	err = json.Unmarshal(b, &s)
	if err != nil {
		panic(fmt.Sprintf("Could not unmarshal config (%s) %v", key, err))
	}

	return s
}

func (c *cachedLoader) MustGetBool(key string) bool {
	b, err := c.Get(key)
	if err != nil {
		panic(fmt.Sprintf("Could not fetch config (%s) %v", key, err))
	}
	var ret bool
	err = json.Unmarshal(b, &ret)
	if err != nil {
		panic(fmt.Sprintf("Could not unmarshal config (%s) %v", key, err))
	}
	return ret
}

func (c *cachedLoader) MustGetInt(key string) int {
	b, err := c.Get(key)
	if err != nil {
		panic(fmt.Sprintf("Could not fetch config (%s) %v", key, err))
	}

	var ret int
	err = json.Unmarshal(b, &ret)
	if err != nil {
		panic(fmt.Sprintf("Could not unmarshal config (%s) %v", key, err))
	}
	return ret
}

func (c *cachedLoader) MustGetDuration(key string) time.Duration {
	s := c.MustGetString(key)
	ret, err := time.ParseDuration(s)
	if err != nil {
		panic(fmt.Sprintf("Could not parse config (%s) into a duration: %v", key, err))
	}
	return ret
}

func NewRandomDNSBalancer(environment string, consulAddr string, cacheTTL time.Duration) (balancer.DNS, error) {
	config := api.DefaultConfig()
	config.Address = consulAddr
	consul, err := api.NewClient(config)
	if err != nil {
		return nil, fmt.Errorf("Could not connect to consul: %v", err)
	}

	r := randomBalancer{}
	r.cache = make(map[string]cachedServiceLocation)
	r.environment = environment
	r.ttl = cacheTTL
	r.consulCatalog = consul.Health()
	return &r, nil
}

func (r *randomBalancer) writeServiceToCache(serviceName string) ([]*balancer.ServiceLocation, error) {
	r.cacheLock.Lock()
	defer r.cacheLock.Unlock()

	if result, ok := r.cache[serviceName]; ok {
		if time.Now().UTC().Before(result.CachedAt.Add(r.ttl)) {
			return result.Services, nil
		}
	}

	consulServices, _, err := r.consulCatalog.Service(serviceName, r.environment, true, nil)
	if err != nil {
		return nil, fmt.Errorf("Error reaching consul for service lookup %v", err)
	}

	if len(consulServices) == 0 {
		return nil, fmt.Errorf("No services found for %s", serviceName)
	}

	var services []*balancer.ServiceLocation
	for _, v := range consulServices {
		s := &balancer.ServiceLocation{}
		s.URL = v.Service.Address
		s.Port = v.Service.Port
		services = append(services, s)
	}

	c := cachedServiceLocation{Services: services, CachedAt: time.Now().UTC()}
	r.cache[serviceName] = c
	return services, nil
}

func StringToLabels(s string) *mesos.Labels {
	labels := &mesos.Labels{Labels: make([]*mesos.Label, 0)}
	if s == "" {
		return labels
	}
	pairs := strings.Split(s, ";")
	for _, pair := range pairs {
		kv := strings.Split(pair, "=")
		key, value := kv[0], kv[1]
		label := &mesos.Label{Key: proto.String(key), Value: proto.String(value)}
		labels.Labels = append(labels.Labels, label)
	}
	return labels
}

func SetClockSequence(seq int) {
	if seq == -1 {
		var b [2]byte
		randomBits(b[:])
		seq = int(b[0])<<8 | int(b[1])
	}
	old_seq := clock_seq
	clock_seq = uint16(seq&0x3fff) | 0x8000
	if old_seq != clock_seq {
		lasttime = 0
	}
}

