func (w *Window) printf(x, y int, a Attributes, format string,
	args ...interface{}) {
	out := fmt.Sprintf(format, args...)
	xx := 0
	c := Cell{}
	c.Fg = a.Fg
	c.Bg = a.Bg
	mx := w.x - x
	var rw int
	for i := 0; i < len(out); i += rw {
		if x+xx+1 > mx {
			break
		}

		v, width := utf8.DecodeRuneInString(out[i:])
		if v == '\x1b' {
			cc, skip, err := DecodeColor(out[i:])
			if err == nil {
				c.Fg = cc.Fg
				c.Bg = cc.Bg
				rw = skip
				continue

			}
		}

		rw = width
		c.Ch = v
		w.setCell(x+xx, y, c)
		xx++
	}
}

func (w *Window) setCell(x, y int, c Cell) {
	c.dirty = true
	pos := x + (y * w.x)
	if pos < len(w.backingStore) {
		w.backingStore[pos] = c
	}
}

func (w *Window) resize(x, y int) {
	w.x = x
	w.y = y
	w.backingStore = make([]Cell, x*y)

	for _, widget := range w.widgets {
		widget.Resize()
	}
}

func (w *Window) render() {
	w.mgr.Render(w)

	for _, widget := range w.widgets {
		widget.Render()
	}

	w.focusWidget()
}

func (w *Window) focusWidget() {
	setCursor(-1, -1)
	if w.focus < 0 {
		for i, widget := range w.widgets {
			if widget.CanFocus() {
				w.focus = i
				widget.Focus()
				return
			}
		}
		return
	}

	if w.focus > len(w.widgets) {
		return
	}

	w.widgets[w.focus].Focus()
}

func (w *Window) focusPrevious() {
	w.focus--
	if w.focus < 0 {
		w.focusWidget()
		return
	}

	for i := w.focus; i > 0; i-- {
		widget := w.widgets[i]
		if !widget.CanFocus() {
			continue
		}
		setCursor(-1, -1)
		w.focus = i
		widget.Focus()
		return
	}

	for i := len(w.widgets) - 1; i > w.focus; i-- {
		widget := w.widgets[i]
		if !widget.CanFocus() {
			continue
		}
		setCursor(-1, -1)
		w.focus = i
		widget.Focus()
		return
	}

}

func (w *Window) keyHandler(ev termbox.Event) (bool, Windower, Widgeter) {
	if w.focus < 0 || w.focus > len(w.widgets) {
		return false, w.mgr, nil
	}
	return w.widgets[w.focus].KeyHandler(ev), w.mgr, w.widgets[w.focus]
}

func Color(at, fg, bg int) (string, error) {
	var a, f, b string

	if at == AttrNA && fg == AttrNA && bg == AttrNA {
		return "", ErrInvalidColor
	}

	switch at {
	case AttrNA:
		break
	case AttrBold, AttrUnderline, AttrReverse, AttrReset:
		a = fmt.Sprintf("%v;", at)
	default:
		return "", ErrInvalidAttribute
	}

	switch {
	case fg == AttrNA:
		break
	case fg >= ColorBlack && fg <= ColorWhite:
		f = fmt.Sprintf("%v;", fg+ANSIFg)
	default:
		return "", ErrInvalidForeground
	}

	switch {
	case bg == AttrNA:
		break
	case bg >= ColorBlack && bg <= ColorWhite:
		b = fmt.Sprintf("%v;", bg+ANSIBg)
	default:
		return "", ErrInvalidBackground
	}

	es := fmt.Sprintf("\x1b[%v%v%v", a, f, b)

	es = es[:len(es)-1] + "m"

	return es, nil
}

func EscapedLen(s string) int {
	if len(s) == 0 {
		return 0
	}

	var rw, total int
	for i := 0; i < len(s); i += rw {
		v, width := utf8.DecodeRuneInString(s[i:])
		if v == '\x1b' {
			_, skip, err := DecodeColor(s[i:])
			if err == nil {
				rw = skip
				total += skip
				continue

			}
		}
		rw = width
	}

	return total
}

func Unescape(s string) string {
	if len(s) == 0 {
		return ""
	}

	var ret string
	var rw int
	for i := 0; i < len(s); i += rw {
		v, width := utf8.DecodeRuneInString(s[i:])
		if v == '\x1b' {
			_, skip, err := DecodeColor(s[i:])
			if err == nil {
				rw = skip
				continue

			}
		}
		ret += string(v)
		rw = width
	}

	return ret
}

func init() {
	work = make(chan func(), 32)
	keyC = make(chan Key, 1024)
	windows = make(map[int]*Window)
	windower2window = make(map[Windower]*Window)

	execute := make(chan bool, 1)
	fa := make([]func(), 0, 20)
	mtx := sync.Mutex{}

	var wg sync.WaitGroup
	wg.Add(2)
	go func() {
		wg.Done()
		for range execute {
			for {
				mtx.Lock()
				if len(fa) == 0 {
					mtx.Unlock()
					break
				}
				f := fa[0]
				fa[0] = nil
				fa = fa[1:]
				mtx.Unlock()

				f()
			}
		}
	}()

	go func() {
		wg.Done()
		for f := range work {
			mtx.Lock()
			fa = append(fa, f)
			mtx.Unlock()

			select {
			case execute <- true:
			default:
			}
		}
	}()
	wg.Wait()
}

func initKeyHandler() {
	for {
		switch ev := termbox.PollEvent(); ev.Type {
		case termbox.EventKey:
			e := ev
			Queue(func() {
				var (
					widget Widgeter
					window Windower
				)
				if focus != nil {
					var used bool
					used, window, widget = focus.keyHandler(e)
					if used {
						flush()
						return
					}
				}

				keyC <- Key{
					Mod:    e.Mod,
					Key:    e.Key,
					Ch:     e.Ch,
					Window: window,
					Widget: widget,
				}
			})

		case termbox.EventResize:
			Queue(func() {
				resizeAndRender(focus)
			})
		case termbox.EventMouse:
		case termbox.EventError:
			return
		}
	}
}

func Init() error {
	rawMtx.Lock()
	defer rawMtx.Unlock()

	if termRaw {
		return ErrAlreadyInitialized
	}

	err := termbox.Init()
	if err != nil {
		return err
	}

	bg = termbox.ColorDefault
	fg = termbox.ColorDefault
	termbox.HideCursor()
	termbox.SetInputMode(termbox.InputAlt)
	_ = termbox.Clear(bg, bg)
	maxX, maxY = termbox.Size()
	_ = termbox.Flush()

	if !keyHandler {
		go initKeyHandler()
		keyHandler = true
	}

	termRaw = true

	return nil
}

func NewWindow(manager Windower) *Window {
	wc := make(chan *Window)
	Queue(func() {
		w := &Window{
			id:           lastWindowID,
			mgr:          manager,
			x:            maxX,
			y:            maxY,
			focus:        -1,
			backingStore: make([]Cell, maxX*maxY),
			widgets:      make([]Widgeter, 0, 16),
		}
		lastWindowID++
		windows[w.id] = w
		windower2window[manager] = w
		manager.Init(w)
		wc <- w
	})
	return <-wc
}

func flush() {
	if focus == nil {
		return
	}
	for y := 0; y < focus.y; y++ {
		for x := 0; x < focus.x; x++ {
			c := focus.getCell(x, y)
			if c == nil {
				continue
			}
			if !c.dirty {
				continue
			}
			c.dirty = false

			termbox.SetCell(x, y, c.Ch, c.Fg, c.Bg)
		}
	}
	_ = termbox.Flush()
}

func focusWindow(w *Window) {
	if w == nil {
		return
	}
	_, found := windows[w.id]
	if !found {
		return
	}
	if focus == w {
		return
	}
	prevFocus = focus
	focus = w

	resizeAndRender(w)
}

func resizeAndRender(w *Window) {
	if w != nil {
		_ = termbox.Clear(bg, bg)
		maxX, maxY = termbox.Size()

		w.resize(maxX, maxY)
		w.render()

		flush()
	}
}

