func (c *Client) Post(metrics []Metric) error {
	series := struct {
		Series []Metric `json:"series,omitempty"`
	}{Series: metrics}

	buf := fetchBuffer()
	defer bufferPool.Put(buf)

	var dst io.Writer = buf
	if !c.DisableCompression {
		zlw := fetcZlibWriter(buf)
		defer zlibWriterPool.Put(zlw)
		defer zlw.Close()

		dst = zlw
	}

	if err := json.NewEncoder(dst).Encode(&series); err != nil {
		return err
	}
	if c, ok := dst.(io.Closer); ok {
		if err := c.Close(); err != nil {
			return err
		}
	}
	return c.post(buf.Bytes(), 0)
}

func MetricID(name string, tags []string) string {
	if len(tags) == 0 {
		return name
	}
	sort.Strings(tags)
	return name + "|" + strings.Join(tags, ",")
}

func SplitMetricID(metricID string) (name string, tags []string) {
	if metricID == "" {
		return "", nil
	}

	pos := strings.LastIndexByte(metricID, '|')
	if pos > 0 && pos < len(metricID)-1 {
		return metricID[:pos], strings.Split(metricID[pos+1:], ",")
	}
	return metricID, nil
}

func NewRateScale(d time.Duration) *Rate {
	return &Rate{
		time: time.Now().UnixNano(),
		unit: d.Seconds(),
	}
}

func (r *Rate) Snapshot() float64 {
	now := time.Now().UnixNano()
	dur := time.Duration(now - atomic.SwapInt64(&r.time, now))
	return r.count.Snapshot() / dur.Seconds() * r.unit
}

func NewDeriveScale(v float64, d time.Duration) *Derive {
	return &Derive{
		value: math.Float64bits(v),
		rate: Rate{
			time: time.Now().UnixNano(),
			unit: d.Seconds(),
		},
	}
}

func (d *Derive) Update(v float64) {
	p := atomic.SwapUint64(&d.value, math.Float64bits(v))
	d.rate.Update(v - math.Float64frombits(p))
}

func (g *Gauge) Update(v float64) {
	atomic.StoreUint64(&g.value, math.Float64bits(v))
}

func (g *Gauge) Snapshot() float64 {
	u := atomic.LoadUint64(&g.value)
	return math.Float64frombits(u)
}

