func (s RethinkStore) FilterBefore(id string, filter map[string]interface{}, count int, skip int, store string, opts ObjectStoreOptions) (rows ObjectRows, err error) {
	rootTerm := r.DB(s.Database).Table(store).Between(
		r.MinVal, id, r.BetweenOpts{RightBound: "closed"}).OrderBy(
		r.OrderByOpts{Index: r.Desc("id")}).Filter(
		s.transformFilter(nil, filter)).Limit(count)
	result, err := rootTerm.Run(s.Session)
	if err != nil {
		return
	}
	if result.Err() != nil {
		return nil, result.Err()
	}
	if result.IsNil() {
		return nil, ErrNotFound
	}
	rows = RethinkRows{result}
	return
}

func (e *EnvVar) Set(key, value string) {
	keyVal := key + "=" + value
	for i, v := range *e {
		env := strings.SplitN(v, "=", 2)
		if len(env) < 2 {
			continue
		}
		if env[0] == key {
			(*e)[i] = keyVal
			return
		}
	}
	*e = append(*e, keyVal)
}

func (e *EnvVar) SetStr(keyVal string) {
	s := strings.SplitN(keyVal, "=", 2)
	if len(s) == 2 {
		e.Set(s[0], s[1])
	}
}

func (e EnvVar) Get(key string) string {
	for _, v := range e {
		env := strings.SplitN(v, "=", 2)
		if len(env) < 2 {
			continue
		}
		if env[0] == key {
			return env[1]
		}
	}
	return ""
}

func (e EnvVar) String() string {
	b := bytes.NewBuffer(nil)
	for _, env := range e {
		if len(strings.SplitN(env, "=", 2)) < 2 {
			continue
		}
		fmt.Fprintln(b, env)
	}
	return b.String()
}

