func (s *Set) Contains(value interface{}) bool {
	s.RLock()
	defer s.RUnlock()
	_, ok := s.m[value]
	return ok
}

func (s *Set) ContainsAll(values ...interface{}) bool {
	s.RLock()
	defer s.RUnlock()
	for _, value := range values {
		_, ok := s.m[value]
		if !ok {
			return false
		}
	}
	return true
