func (s *Set) ContainsFunc(f func(interface{}) bool) bool {
	s.RLock()
	defer s.RUnlock()
	for k := range s.m {
		if f(k) {
			return true
		}
	}
	return false
}

func (s *Set) Clear() {
	s.Lock()
	defer s.Unlock()
	s.m = make(map[interface{}]struct{})
}

func (s *Set) Iterator() Iterator {
	s.RLock()
	defer s.RUnlock()
	iterChan := make(chan interface{}, len(s.m))
	for k := range s.m {
		iterChan <- k
	}
	close(iterChan)
	return IterFunc(func() (interface{}, bool) {
		value, ok := <-iterChan
		return value, ok
	})
}

func (s *Set) Items() []interface{} {
	s.RLock()
	defer s.RUnlock()
	items := make([]interface{}, len(s.m))
	i := 0
	for k := range s.m {
		items[i] = k
		i++
	}
	return items
}

func (s *Set) ItemsFunc(f func(value interface{}) bool) []interface{} {
	s.RLock()
	defer s.RUnlock()
	items := []interface{}{}
	for k := range s.m {
		if f(k) {
			items = append(items, k)
		}
	}
	return items
}

func (h holidaysUSNational) fixWeekend(in time.Time) time.Time {
	switch in.Weekday() {
	case time.Saturday:
		return in.Add(-1 * 24 * time.Hour)
	case time.Sunday:
		return in.Add(1 * 24 * time.Hour)
	default:
		return in
	}
}

func GetHolidays(countryCode string, year int) ([]Holiday, error) {
	requiredCodes := []string{countryCode}
	result := []Holiday{}

	for len(requiredCodes) > 0 {
		cc := requiredCodes[0]
		hds, ok := holidayProviders[cc]
		if !ok {
			return nil, HolidayDataNotFoundError
		}

		requiredCodes = append(requiredCodes, hds.GetIncludes()...)
		result = append(result, hds.GetHolidays(year)...)

		requiredCodes = requiredCodes[1:]
	}

	sort.Sort(holidays(result))

	return result, nil
}

