func (c *Conn) send(msg interface{}) error {
	if !c.connected.Load().(bool) {
		return errors.New("use of closed connection")
	}

	return websocket.JSON.Send(c.ws.Load().(*websocket.Conn), msg)
}

func (c *Conn) receive(msg *message) error {
	if !c.connected.Load().(bool) {
		return errors.New("use of closed connection")
	}

	return websocket.JSON.Receive(c.ws.Load().(*websocket.Conn), &msg)
}

func (c *Conn) setConn(ws *websocket.Conn) error {
	c.ws.Store(ws)
	c.connected.Store(true)
	if err := ws.SetDeadline(time.Now().Add(c.deadline)); err != nil {
		return fmt.Errorf("conn: error while setting websocket connection deadline: %v", err)
	}
	return nil
}

func NewPbo(path string) (*Pbo, error) {
	file, err := os.Open(path)
	if err != nil {
		return nil, err
	}

	pbo := Pbo{
		file: file,
	}

	reader := bufio.NewReader(file)

	for {
		entry := readEntry(reader)
		if entry.Flag == ProductEntry {
			extension := HeaderExtension{
				FileEntry: entry,
			}

			extension.ReadExtendedFields(reader)
			pbo.HeaderExtension = &extension

			pbo.dataOffset += int64(extension.EntrySize())

			continue
		}

		pbo.dataOffset += int64(entry.EntrySize())

		if entry.IsNull() {
			break
		}

		entry.pbo = &pbo
		pbo.Entries = append(pbo.Entries, entry)
	}

	baseOffset := pbo.dataOffset
	for i := range pbo.Entries {
		entry := &pbo.Entries[i]
		entry.dataOffset = baseOffset
		baseOffset += int64(entry.DataBlockSize)
	}

	return &pbo, nil
}

