func (c *ConfigArg) UnmarshalBinary(b []byte) error {
	if len(b) < configArgLen {
		return io.ErrUnexpectedEOF
	}

	c.BufferCount = binary.BigEndian.Uint16(b[0:2])
	c.FirmwareVersion = binary.BigEndian.Uint16(b[2:4])
	c.SectorCount = b[4]

	c.Version = uint8(b[5] >> 4)

	c.Command = ConfigCommand(b[5] & 0x0f)

	c.StringLength = binary.BigEndian.Uint16(b[6:8])
	if len(b[8:]) < int(c.StringLength) {
		return io.ErrUnexpectedEOF
	}
	if c.StringLength > 1024 {
		return ErrorBadArgumentParameter
	}

	d := make([]byte, c.StringLength)
	copy(d, b[8:])
	c.String = d

	return nil
}

func ataIdentify(r *ATAArg, rs io.ReadSeeker) (*ATAArg, error) {
	if r.CmdStatus != ATACmdStatusIdentify {
		return nil, errATAAbort
	}

	if r.SectorCount != 1 {
		return nil, errATAAbort
	}

	ident, ok := rs.(Identifier)
	if !ok {
		return nil, ErrNotImplemented
	}

	id, err := ident.Identify()
	if err != nil {
		return nil, err
	}

	return &ATAArg{
		CmdStatus: ATACmdStatusReadyStatus,
		Data:      id[:],
	}, nil
}

func ataRead(r *ATAArg, rs io.ReadSeeker) (*ATAArg, error) {
	if r.CmdStatus != ATACmdStatusRead28Bit && r.CmdStatus != ATACmdStatusRead48Bit {
		return nil, errATAAbort
	}

	if r.FlagWrite {
		return nil, errATAAbort
	}

	offset := calculateLBA(r.LBA, r.FlagLBA48Extended) * sectorSize
	if _, err := rs.Seek(offset, os.SEEK_SET); err != nil {
		return nil, err
	}

	b := make([]byte, int(r.SectorCount)*sectorSize)
	n, err := rs.Read(b)
	if err != nil {
		return nil, err
	}

	if sectors := n / sectorSize; sectors != int(r.SectorCount) {
		return nil, errATAAbort
	}

	return &ATAArg{
		CmdStatus: ATACmdStatusReadyStatus,
		Data:      b,
	}, nil
}

func ataWrite(r *ATAArg, rs io.ReadSeeker) (*ATAArg, error) {
	if r.CmdStatus != ATACmdStatusWrite28Bit && r.CmdStatus != ATACmdStatusWrite48Bit {
		return nil, errATAAbort
	}

	if !r.FlagWrite {
		return nil, errATAAbort
	}

	if sectors := len(r.Data) / sectorSize; sectors != int(r.SectorCount) {
		return nil, errATAAbort
	}

	rws, ok := rs.(io.ReadWriteSeeker)
	if !ok {
		return nil, errATAAbort
	}


	offset := calculateLBA(r.LBA, r.FlagLBA48Extended) * sectorSize
	if _, err := rs.Seek(offset, os.SEEK_SET); err != nil {
		return nil, err
	}

	n, err := rws.Write(r.Data)
	if err != nil {
		return nil, err
	}

	if sectors := n / sectorSize; sectors != int(r.SectorCount) {
		return nil, errATAAbort
	}

	return &ATAArg{
		CmdStatus: ATACmdStatusReadyStatus,
	}, nil
}

func calculateLBA(rlba [6]uint8, is48Bit bool) int64 {
	b := []byte{
		rlba[0],
		rlba[1],
		rlba[2],
		rlba[3],
		rlba[4],
		rlba[5],
		0,
		0,
	}
	lba := binary.LittleEndian.Uint64(b)

	if is48Bit {
		lba &= 0x0000ffffffffffff
	} else {
		lba &= 0x0fffffff
	}

	return int64(lba)
}

func (r *ReserveReleaseArg) MarshalBinary() ([]byte, error) {
	if int(r.NMACs) != len(r.MACs) {
		return nil, ErrorBadArgumentParameter
	}

	b := make([]byte, reserveReleaseArgLen+(r.NMACs*6))

	b[0] = uint8(r.Command)
	b[1] = uint8(r.NMACs)

	n := 2
	for _, m := range r.MACs {
		if len(m) != 6 {
			return nil, ErrorBadArgumentParameter
		}

		copy(b[n:n+6], m)
		n += 6
	}

	return b, nil
}

func (r *ReserveReleaseArg) UnmarshalBinary(b []byte) error {
	if len(b) < reserveReleaseArgLen {
		return io.ErrUnexpectedEOF
	}

	r.Command = ReserveReleaseCommand(b[0])
	r.NMACs = b[1]

	if len(b[2:]) != (6 * int(r.NMACs)) {
		return io.ErrUnexpectedEOF
	}

	r.MACs = make([]net.HardwareAddr, r.NMACs)
	for i := 0; i < int(r.NMACs); i++ {
		m := make(net.HardwareAddr, 6)
		copy(m, b[2+(i*6):2+(i*6)+6])
		r.MACs[i] = m
	}

	return nil
}

func (a *ATAArg) MarshalBinary() ([]byte, error) {
	b := make([]byte, ataArgLen+len(a.Data))

	var flags uint8
	if a.FlagLBA48Extended {
		flags |= (1 << 6)
	}
	if a.FlagATADeviceHeadRegister {
		flags |= (1 << 4)
	}
	if a.FlagAsynchronous {
		flags |= (1 << 1)
	}
	if a.FlagWrite {
		flags |= 1
	}
	b[0] = flags

	b[1] = a.ErrFeature
	b[2] = a.SectorCount
	b[3] = uint8(a.CmdStatus)
	b[4] = a.LBA[0]
	b[5] = a.LBA[1]
	b[6] = a.LBA[2]
	b[7] = a.LBA[3]
	b[8] = a.LBA[4]
	b[9] = a.LBA[5]


	copy(b[12:], a.Data)

	return b, nil
}

