func NewMulti(vals ...interface{}) LogBackend {
	if len(vals)%2 != 0 {
		Fail(e.New("parameters must be in pair of LogBackend and Formatter"))
		return nil
	}
	l := len(vals) / 2
	mp := make([]LogBackend, 0, l)
	for i := 0; i < len(vals); i += 2 {
		bak, ok := vals[i].(LogBackend)
		if !ok {
			Fail(e.New("not a LogBackend"))
			return nil
		}
		f, ok := vals[i+1].(Formatter)
		if !ok {
			Fail(e.New("not a Formatter"))
			return nil
		}
		bak.F(f)
		mp = append(mp, bak)
	}
	return &MultiLog{
		mp: mp,
	}
}

func (mp *MultiLog) OuterLog(level Level, tags ...string) io.Writer {
	if mp.chouter != nil {
		return &outer{
			ch:  mp.chouter,
			buf: make([]byte, 0),
		}
	}
	mp.chclose = make(chan chan struct{})
	mp.chouter = make(chan []byte)
	if len(mp.mp) < 2 {
		return nil
	}
	f := mp.mp[0].GetF()
	logger := f.NewEntry(mp).Tag("outer").EntryLevel(level)
	go func() {
		for {
			select {
			case buf := <-mp.chouter:
				logger.Tag(tags...).Println(string(buf))
			case ch := <-mp.chclose:
				ch <- struct{}{}
				return
			}
		}
	}()
	return &outer{
		ch:  mp.chouter,
		buf: make([]byte, 0),
	}
}

