func (handler *SyslogHandler) Handle(record *Record) error {

	if handler.writter == nil {
		writter, err := syslog.Dial(
			handler.Network,
			handler.Address,
			handler.Facility|handler.Severity,
			handler.Tag,
		)

		if err != nil {
			return err
		}
		handler.writter = writter
	}

	msg := handler.Formatter.Format(record)

	switch record.Level {
	case EMERGENCY:
		return handler.writter.Emerg(msg)
	case ALERT:
		return handler.writter.Alert(msg)
	case CRITICAL:
		return handler.writter.Crit(msg)
	case ERROR:
		return handler.writter.Err(msg)
	case WARNING:
		return handler.writter.Warning(msg)
	case NOTICE:
		return handler.writter.Notice(msg)
	case INFO:
		return handler.writter.Info(msg)
	default:
		return handler.writter.Debug(msg)
	}
}

func (handler *SyslogHandler) Close() error {
	if handler.writter == nil {
		return nil
	}
	return handler.writter.Close()
}

func hasDatePrefix(s string) bool {
	if len(s) < 10 {
		return false
	}
	var count int
	for i, r := range s {
		if count != i {
			return false
		}
		switch i {
		case 4, 7:
			if r != '-' {
				return false
			}
		default:
			if !isDigit(r) {
				return false
			}
		}
		if i == 9 {
			if s[5] == '1' {
				if s[6] > '2' {
					return false
				}
			} else if s[5] == '0' {
				if s[6] == '0' {
					return false
				}
			} else {
				return false
			}

			if s[8] == '0' {
				if s[9] == '0' {
					return false
				}
			} else if s[8] == '3' {
				if s[9] > '1' {
					return false
				}
			} else if s[8] != '1' && s[8] != '2' {
				return false
			}

			return true
		}
		count += 1
	}

	return true
}

func (f RuneMatcherFunc) Match(str string) (offset int, matchStr string) {
	offset = -1
	length := len(str)
	if length == 0 {
		return
	}

	for i, r := range str {
		if f(r) {
			continue
		}
		if i != 0 {
			offset = i
			matchStr = str[:i]
			return
		}
		return
	}

	offset = length
	matchStr = str
	return
}

func (m *SuffixMatcher) Match(str string) (offset int, matchStr string) {
	offset = -1

	d := len(str) - len(m.suffix)
	if d < 1 {
		return
	}

	for i, r := range str {
		if i > d {
			return
		}

		if i != 0 && m.suffix == str[i:i+len(m.suffix)] {
			offset = i + len(m.suffix)
			matchStr = str[:i]
			return
		}

		if !m.matcher.MatchRune(r) {
			return
		}
	}
	return
}

func (m *SuffixMatcher) MatchRune(r rune) bool {
	return m.matcher.MatchRune(r)
}

func (m *FixedLengthMatcher) Match(s string) (offset int, matchStr string) {
	if len(s) < m.length || !m.match(s) {
		offset = -1
		return
	}
	return m.length, s[:m.length]
}

func (b *RefCountBox) Alloc() (DB, error) {
	b.Lock()
	defer b.Unlock()

	if b.db.DB == nil {
		if b.DataPath == nil {
			return DB{}, errorsp.WithStacks(ErrBoxDataPathNotSpecified)
		}
		var db DB
		var err error
		if b.OpenFunc == nil {
			db, err = Open(b.DataPath(), 0644, nil)
		} else {
			db, err = b.OpenFunc(b.DataPath())
		}
		if err != nil {
			return DB{}, errorsp.WithStacks(err)
		}
		b.db, b.count = db, 0
	}
	b.count++
	return b.db, nil
}

func (b *RefCountBox) Free() {
	b.Lock()
	defer b.Unlock()

	b.count--
	if b.count == 0 {
		b.db.Close()
		b.db = DB{}
	}
}

