func (t Tournaments) GroupByMonths(season int) map[time.Month]Tournaments {
	byMonth := make(map[time.Month]Tournaments)

	for _, entry := range t {
		y, m := entry.Info.Scheduled.Year(), entry.Info.Scheduled.Month()
		if y == season {
			byMonth[m] = append(byMonth[m], entry)
		}
	}

	return byMonth
}

func validateTournamentInfo(info Info) error {
	if info.Scheduled.IsZero() {
		return errors.New("Tournament needs scheduled date")
	}
	if info.Stake == 0 {
		return errors.New("Tournament needs a stake")
	}
	if info.Season == 0 {
		return errors.New("Tournament needs a season")
	}
	return nil
}

func NewTournament(tdata Info) (*Tournament, error) {
	if err := validateTournamentInfo(tdata); err != nil {
		return nil, errors.New(err.Error() + " - Could not create tournament")
	}

	t := new(Tournament)
	t.UUID, _ = uuid.V4()
	if err := mergo.MergeWithOverwrite(&t.Info, tdata); err != nil {
		return nil, errors.New(err.Error() + " - Could not set initial tournament data")
	}
	fixupTournamentInfo(&t.Info, tdata)
	if err := storage.Store(t); err != nil {
		return nil, errors.New(err.Error() + " - Could not write tournament to storage")
	}
	return t, nil
}

func (s StringSlice) IndexOf(str string) int {
	for i, v := range s {
		if str == v {
			return i
		}
	}

	return -1
}

func (s StringSlice) IndexOfIgnoreCase(str string) int {
	str = strings.ToLower(str)
	for i, v := range s {
		if str == strings.ToLower(v) {
			return i
		}
	}

	return -1
}

func NewCache(d time.Duration) *Cache {
	return &Cache{
		values:   make(map[string]*cacheItem),
		lifetime: d,
	}
}

func (s *Cache) Count() int {
	if s.removeExpired() == raiqub.WriteLocked {
		defer s.Unlock()
	} else {
		defer s.RUnlock()
	}

	return len(s.values)
}

func (s *Cache) Flush() {
	s.Lock()
	defer s.Unlock()

	s.values = make(map[string]*cacheItem)
}

func (s *Cache) removeExpired() raiqub.LockStatus {
	writeLocked := false
	s.RLock()
	for i := range s.values {
		if s.values[i].IsExpired() {
			if !writeLocked {
				s.RUnlock()
				s.Lock()
				writeLocked = true
			}
			delete(s.values, i)
		}
	}

	if writeLocked {
		return raiqub.WriteLocked
	} else {
		return raiqub.ReadLocked
	}
}

func NewImage(d *Docker, name string) *Image {
	return &Image{
		docker: d,
		name:   name,
	}
}

func (s *Image) Exists() bool {
	out, err := s.docker.Run("images", "--no-trunc")
	if err != nil {
		return false
	}

	return strings.Contains(out, s.name)
}

func (s *Image) Pull() error {
	_, err := s.docker.Run("pull", s.name)
	if err != nil {
		return err
	}

	return nil
}

func (s *Image) Run(cfg *RunConfig) (*Container, error) {
	args := make([]string, 0, len(cfg.Options)+len(cfg.Args)+1)
	args = append(args, cfg.Options...)
	args = append(args, s.name)
	args = append(args, cfg.Args...)

	out, err := s.docker.Run("run", args...)
	if err != nil {
		return nil, err
	}

	container := &Container{
		docker: s.docker,
		id:     strings.TrimSpace(out),
	}
	if container.id == "" {
		return nil, UnexpectedOutputError(
			"Unexpected empty output when running docker container")
	}

	return container, nil
}

func (s *Image) Setup() error {
	if !s.docker.HasBin() {
		return DockerBinNotFound(s.docker.binCmd)
	}

	if !s.Exists() {
		if err := s.Pull(); err != nil {
			return err
		}
	}

	return nil
}

