func (b *Bus) Subscribe(h Handler) bool {
	b.mu.Lock()
	defer b.mu.Unlock()

	for _, v := range b.handlers {
		if v == h {
			return false
		}
	}

	b.handlers = append(b.handlers, h)
	return true
}

func (b *Bus) Unsubscribe(h Handler) bool {
	b.mu.Lock()
	defer b.mu.Unlock()

	for i, v := range b.handlers {
		if v == h {
			b.handlers = append(b.handlers[:i], b.handlers[i+1:]...)
			return true
		}
	}

	return false
}

func (b *Bus) Publish(eventName string, eventBody interface{}) {
	e := NewEvent(eventName, eventBody)

	b.mu.RLock()
	defer b.mu.RUnlock()
	for _, h := range b.handlers {
		h.Handle(e)
	}
}

func HandleOnly(h Handler, names ...string) Handler {
	return HandlerFunc(func(e Event) {
		for _, name := range names {
			if e.Name() == name {
				h.Handle(e)
				break
			}
		}
	})
}

func ContextWithPublisher(ctx context.Context, pub Publisher) context.Context {
	return context.WithValue(ctx, KeyPublisher, pub)
}

func PublisherContext(ctx context.Context) Publisher {
	pub, ok := ctx.Value(KeyPublisher).(Publisher)
	if !ok {
		return nil
	}

	return pub
}

func PublishNamedEvent(pub Publisher, eventBody interface{}) {
	name := reflect.TypeOf(eventBody).Name()
	pub.Publish(name, eventBody)
}

func PublishEventContext(ctx context.Context, eventName string, eventBody interface{}) {
	pub := PublisherContext(ctx)
	if pub == nil {
		return
	}

	pub.Publish(eventName, eventBody)
}

func PublishNamedEventContext(ctx context.Context, eventBody interface{}) {
	name := reflect.TypeOf(eventBody).Name()
	PublishEventContext(ctx, name, eventBody)
}
